+      target: productId,
       targetType: 'Product',
     });

     let isLiked;
     let likes;

     if (existingLike) {
       // Unlike
       await Like.deleteOne({ _id: existingLike._id });
       product.likes = Math.max(0, (product.likes || 0) - 1);
       product.isLiked = false;
       await product.save();
       isLiked = false;
     } else {
       // Like
       await Like.create({
         user: sessionUser.userId,
