      return new Response(
        JSON.stringify({ message: 'Product not found' }),
        { status: 404, headers: { 'Content-Type': 'application/json' } }
      );
    }

    const product = await Product.findById(productId);
    if (!product) {
      return new Response(
        JSON.stringify({ message: 'Product not found' }),
        { status: 404, headers: { 'Content-Type': 'application/json' } }
