                   {Math.min(pagination.page * pagination.limit, pagination.total)} of{" "}
                   {pagination.total} buyers
                 </p>
                 <div className="flex items-center gap-2">
                   <Button
                     variant="outline"
                     size="sm"
                     disabled={pagination.page <= 1}
