                   </span>
                   <Button
                     variant="outline"
                     size="sm"
                     disabled={pagination.page >= pagination.pages}
                     onClick={() => setPagination(prev => ({ ...prev, page: prev.page + 1 }))}
                   >
                     Next
                     <ChevronRight className="h-4 w-4" />
                   </Button>
                 </div>
               </div>
             </>
           )}
         </CardContent>
       </Card>
     </div>
   );
 }

