         body: JSON.stringify({ action }),
       });

       if (res.ok) {
         toast({
           title: "Success",
           description: `Store ${action}d successfully`,
         });
         fetchStores();
       } else {
         const data = await res.json();
         toast({
           title: "Error",
           description: data.error || "Action failed",
           variant: "destructive",
         });
       }
     } catch (error) {
       console.error("Error performing action:", error);
