 const statusConfig = {
   pending: { label: "Order Placed", color: "bg-yellow-100 text-yellow-800", icon: Clock },
   confirmed: { label: "Confirmed", color: "bg-blue-100 text-blue-800", icon: CheckCircle2 },
   processing: { label: "Processing", color: "bg-purple-100 text-purple-800", icon: Package },
   shipped: { label: "Shipped", color: "bg-indigo-100 text-indigo-800", icon: Truck },
   delivered: { label: "Delivered", color: "bg-green-100 text-green-800", icon: CheckCircle2 },
   cancelled: { label: "Cancelled", color: "bg-red-100 text-red-800", icon: Package },
 };

 export default function PurchaseDetailPage() {
   const params = useParams();
   const router = useRouter();
   const [order, setOrder] = useState(null);
   const [loading, setLoading] = useState(true);
   const [trackingStatus, setTrackingStatus] = useState("");
   const [updating, setUpdating] = useState(false);

   useEffect(() => {
     if (params.id) {
       fetchOrder();
     }
   }, [params.id]);

   useEffect(() => {
     if (order?.trackingNumber) {
       fetchTracking();
     }
   }, [order?.trackingNumber]);

   const fetchTracking = async () => {
     try {
       const res = await fetch(`/api/orders/${params.id}/track`);
       if (res.ok) {
         const data = await res.json();
         if (data?.tracking?.status) {
           setTrackingStatus(data.tracking.status);
         } else if (data?.tracking?.state) {
           setTrackingStatus(data.tracking.state);
         }
       }
     } catch (error) {
       console.error("Failed to fetch tracking details:", error);
     }
   };

   const handleConfirmDelivery = async () => {
     try {
       setUpdating(true);
       const res = await fetch(`/api/orders/${params.id}/status`, {
         method: "PUT",
         headers: { "Content-Type": "application/json" },
         body: JSON.stringify({ status: "delivered" }),
       });
       const data = await res.json();
       if (!res.ok) throw new Error(data.error || "Failed to confirm delivery");

       toast({
         title: "Delivery Confirmed",
         description: "The order has been marked as delivered and funds released.",
       });
       fetchOrder();
     } catch (error) {
       toast({
         title: "Error",
         description: error.message,
         variant: "destructive",
       });
     } finally {
       setUpdating(false);
     }
   };

   const fetchOrder = async () => {
     try {
       setLoading(true);
       const res = await fetch(`/api/orders/${params.id}`);
       if (!res.ok) throw new Error("Failed to fetch order");

       const data = await res.json();
       setOrder(data);
     } catch (error) {
       console.error("Error fetching order:", error);
       toast({
         title: "Error",
         description: "Failed to load order details",
         variant: "destructive",
       });
     } finally {
       setLoading(false);
     }
   };

   if (loading) {
     return (
       <DashboardShell>
         <div className="text-center py-12">Loading order details...</div>
       </DashboardShell>
     );
   }

   if (!order) {
     return (
       <DashboardShell>
         <div className="text-center py-12">Order not found</div>
       </DashboardShell>
     );
   }

   // Timeline for order tracking
   const timeline = [
     { status: 'pending', label: 'Order Placed', date: order.createdAt },
     { status: 'confirmed', label: 'Confirmed', date: order.confirmedAt },
     { status: 'shipped', label: 'Shipped', date: order.shippedAt },
     { status: 'delivered', label: 'Delivered', date: order.deliveredAt },
   ];

   const currentStatusIndex = timeline.findIndex(t => t.status === order.status);

   return (
     <DashboardShell>
       <div className="space-y-6">
         <div className="flex items-center gap-4">
           <Button variant="outline" size="icon" onClick={() => router.back()}>
