   "Limpopo",
   "Mpumalanga",
   "Northern Cape",
   "North West"
 ];
 
 export default function StoreFilterSort({ stores = [], onLike, selectedStoreId, viewMode, onViewModeChange }) {
   const [search, setSearch] = React.useState('');
   const [province, setProvince] = React.useState('All Provinces');
   const [sortBy, setSortBy] = React.useState('createdAt');
 
   const filteredStores = React.useMemo(() => {
     if (!stores) return [];
 
     let list = stores.slice();
 
     // Filter by search query
     if (search.trim()) {
       const q = search.toLowerCase();
       list = list.filter(
         (store) =>
           (store.storename || '')
             .toString()
             .toLowerCase()
             .includes(q) ||
           (store.about || '')
             .toString()
             .toLowerCase()
             .includes(q)
       );
     }
 
     // Filter by province
     if (province !== 'All Provinces') {
       list = list.filter((store) => store.province === province);
     }
 
     // Sort stores
     if (sortBy === 'storename') {
       list.sort((a, b) => 
         (a.storename || '').localeCompare(b.storename || '')
       );
     } else if (sortBy === 'city') {
       list.sort((a, b) => 
         (a.city || '').localeCompare(b.city || '')
       );
     } else if (sortBy === 'province') {
       list.sort((a, b) => 
         (a.province || '').localeCompare(b.province || '')
       );
     } else {
       // Default: sort by createdAt (newest first)
       list.sort(
         (a, b) =>
           new Date(b.createdAt || b._createdAt || 0) -
